changeSet.sql:
-- 0) Trim surrounding whitespace (the normalizer trims before anything else; some -- historical links were stored with leading spaces/tabs/newlines). Uses a regex so -- it strips all whitespace classes, matching Java's String.trim(), not just spaces. UPDATE orders SET link = regexp_replace(link, '^\s+|\s+$', '', 'g') WHERE link ~ '^\s' OR link ~ '\s$';
-- 1) Strip query string and fragment (the normalizer drops both) UPDATE orders SET link = regexp_replace(link, '[?#].*$', '') WHERE link ~* 'instagram\.com' AND link ~ '[?#]';
-- 2) Force https and canonicalize host to www.instagram.com (covers http://, -- instagram.com and m.instagram.com; case-insensitive on the host) UPDATE orders SET link = regexp_replace(link, '^https?://(www\.|m\.)?instagram\.com', 'https://www.instagram.com', 'i') WHERE link ~* '^https?://(www\.|m\.)?instagram\.com' AND link !~ '^https://www\.instagram\.com';
-- 2b) Strip a leading @ from the profile path (the normalizer drops it: -- instagram.com/@handle -> instagram.com/handle) UPDATE orders SET link = regexp_replace(link, '^(https://www\.instagram\.com)/@', '\1/') WHERE link ~ '^https://www\.instagram\.com/@';
-- 3) Rewrite /reel/ and /reels/ to /p/ (Instagram serves the same content) UPDATE orders SET link = regexp_replace(link, '/reels?/', '/p/', 'gi') WHERE link ~* '^https://www\.instagram\.com/reels?/';
-- 4) Truncate mobile share tokens: /p/<11-char shortcode><token> -> /p/<shortcode>/ UPDATE orders SET link = regexp_replace( link, '(/p/)([A-Za-z0-9_-]{11})[A-Za-z0-9_-]+/?$', '\1\2/', 'i') WHERE link ~* '^https://www\.instagram\.com/p/[A-Za-z0-9_-]{12,}';
-- 5) Lowercase the profile handle (single-segment profile URLs only; content -- shortcodes have two+ segments and reserved keywords are excluded). The rebuild -- also appends the trailing slash for profiles. UPDATE orders SET link = 'https://www.instagram.com/' || lower(substring(link from '^https://www\.instagram\.com/([^/]+)/?$')) || '/' WHERE link ~ '^https://www\.instagram\.com/[^/]+/?$' AND lower(substring(link from '^https://www\.instagram\.com/([^/]+)/?$')) NOT IN ('p','reel','reels','tv','stories','explore','s','tagged') AND link <> 'https://www.instagram.com/' || lower(substring(link from '^https://www\.instagram\.com/([^/]+)/?$')) || '/';
-- 6) Ensure a trailing slash on every Instagram URL — the normalizer appends one to -- all links, including content URLs (/p/…), whose shortcode case is left intact. -- Without this, /p/ABC and /p/ABC/ would remain separate quota keys. UPDATE orders SET link = link || '/' WHERE link ~ '^https://www\.instagram\.com/' AND link !~ '/$';
